module chacha_simple (  
    input wire [31:0] cipher_key,  
    input wire [31:0] nonce,  
    input wire [31:0] block_index,  
    output reg [31:0] keystream  
);  
    always @(cipher_key, nonce, block_index) begin  
        keystream = (cipher_key + nonce + block_index) % 32'hFFFFFFFF;  
    end  
endmodule
